import java.util.*;

class Main {
    public static List<List<Integer>> sumWeights(List<List<Integer>> items1, List<List<Integer>> items2) {
        Map<Integer, Integer> weightSums = new TreeMap<>();
        List<List<Integer>> result = new ArrayList<>();

        for (List<Integer> item : items1) {
            weightSums.put(item.get(0), weightSums.getOrDefault(item.get(0), 0) + item.get(1));
        }
        for (List<Integer> item : items2) {
            weightSums.put(item.get(0), weightSums.getOrDefault(item.get(0), 0) + item.get(1));
        }

        for (Map.Entry<Integer, Integer> entry : weightSums.entrySet()) {
            result.add(Arrays.asList(entry.getKey(), entry.getValue()));
        }

        return result;
    }
}
